type JobStatEntry  = { base: number; inc: number; levels?: Record<string,number>; maxLevel?: number };
type JobRankData   = { stats: Record<string,JobStatEntry> };
type Job = {
  generation: 1 | 2;
  type?: "combat" | "non-combat";
  category?: string;
  icon?: string;
  ranks: Record<string,JobRankData>;
  shield?: "can" | "cannot";
  weaponEquip?: Partial<Record<string,WeaponValue>>;
  skillAccess?: SkillAccessMap;
  skills: string[];
  shops?: string[];
  notes?: string;
};
type SharedPair = { id: string; jobA: string; jobB: string; children: string[]; affinity?: string };

type SharedData = {
  jobs: Record<string,Job>;
  statIcons: Record<string,string>;
  weaponCategories?: string[];
  pairs?: SharedPair[];
};

type JobsTableGenFilter = "all" | "1" | "2";
type JobsTableTypeFilter = "all" | "combat" | "non-combat";
type JobsTableSortDir = "asc" | "desc";
type JobsTablePrefs = {
  search: string;
  genFilter: JobsTableGenFilter;
  typeFilter: JobsTableTypeFilter;
  excludedJobs: string[];
  includedJobs: string[];
  favsOnly: boolean;
  sortCol: string;
  sortDir: JobsTableSortDir;
  sortByGrowth: boolean;
};

function getLandOrShopHref(entry: string) {
  const { buildingName } = splitBuildingRankNote(entry);
  return getShopHref(buildingName)
    ?? (JOB_BUILDING_ROUTE_NAMES.has(buildingName) ? `/houses?tab=houses&search=${encodeURIComponent(buildingName)}` : null);
}

function useUserName() {
  const [name, setName] = useState(() => localStorage.getItem("ka_username") ?? "");
  const save = (nextName: string) => {
    setName(nextName);
    localStorage.setItem("ka_username", nextName);
  };
  return { name, save };
}

function statAtLevel(entry: JobStatEntry, level: number): number {
  const ov = entry.levels?.[String(level)];
  if (ov !== undefined) return ov;
  return entry.base + (level - 1) * entry.inc;
}

const STAT_DISPLAY_ALIASES: Record<string, string[]> = { Speed: ["Move", "Movement"] };

function getJobStatEntry(job: Job, rank: string, stat: string): JobStatEntry | null {
  const stats = job.ranks[rank]?.stats ?? job.ranks[Object.keys(job.ranks)[0]]?.stats ?? {};
  const aliases = [stat, ...(STAT_DISPLAY_ALIASES[stat] ?? [])];
  let combined: JobStatEntry | null = null;
  for (const name of aliases) {
    const entry = stats[name];
    if (!entry) continue;
    combined = combined
      ? { base: combined.base + entry.base, inc: combined.inc + entry.inc }
      : { ...entry };
  }
  return combined;
}

function getJobStatValue(job: Job, rank: string, stat: string, level: number): number | null {
  const entry = getJobStatEntry(job, rank, stat);
  return entry ? statAtLevel(entry, clampLevel(level)) : null;
}

function getAwakeningStatLevel(job: Job, rank: string, stat: string, awakening: number, fallbackLevel = 1): number {
  const stats = job.ranks[rank]?.stats ?? {};
  const aliases = [stat, ...(STAT_DISPLAY_ALIASES[stat] ?? [])];
  const baseMax = aliases.reduce<number>((maxSoFar, alias) => {
    const candidate = stats[alias]?.maxLevel;
    return typeof candidate === "number" ? Math.max(maxSoFar, candidate) : maxSoFar;
  }, 0);
  return baseMax > 0 ? clampLevel(baseMax + AWAKENING_LEVEL_BONUS * awakening) : clampLevel(fallbackLevel);
}

const JOBS_TABLE_PREFS_KEY = "ka_jobs_table_prefs_v1";

function loadJobsTablePrefs(): JobsTablePrefs | null {
  if (typeof window === "undefined") return null;
  try {
    const raw = localStorage.getItem(JOBS_TABLE_PREFS_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as Partial<JobsTablePrefs>;
    return {
      search: typeof parsed.search === "string" ? parsed.search : "",
      genFilter: parsed.genFilter === "1" || parsed.genFilter === "2" ? parsed.genFilter : "all",
      typeFilter: parsed.typeFilter === "combat" || parsed.typeFilter === "non-combat" ? parsed.typeFilter : "all",
      excludedJobs: Array.isArray(parsed.excludedJobs) ? parsed.excludedJobs.filter((v): v is string => typeof v === "string") : [],
      includedJobs: Array.isArray(parsed.includedJobs) ? parsed.includedJobs.filter((v): v is string => typeof v === "string") : [],
      favsOnly: Boolean(parsed.favsOnly),
      sortCol: typeof parsed.sortCol === "string" ? parsed.sortCol : "",
      sortDir: parsed.sortDir === "asc" ? "asc" : "desc",
      sortByGrowth: Boolean(parsed.sortByGrowth),
    };
  } catch {
    return null;
  }
}

function saveJobsTablePrefs(prefs: JobsTablePrefs) {
  if (typeof window === "undefined") return;
  localStorage.setItem(JOBS_TABLE_PREFS_KEY, JSON.stringify(prefs));
}

function useFavorites() {
  const [favs, setFavs] = useState<Set<string>>(() => {
    try {
      const stored = localStorage.getItem("ka_fav_jobs");
      return new Set(stored ? JSON.parse(stored) : []);
    } catch { return new Set(); }
  });
  const toggle = (name: string) => {
    setFavs((prev) => {
      const next = new Set(prev);
      if (next.has(name)) next.delete(name); else next.add(name);
      localStorage.setItem("ka_fav_jobs", JSON.stringify([...next]));
      return next;
    });
  };
  return { favs, toggle };
}

function useSharedData() {
  return useQuery({
    queryKey: ["ka-shared"],
    queryFn: async () => withCategoryBattleTypes(await fetchSharedWithFallback<SharedData>(apiUrl("/shared"))),
    initialData: () => withCategoryBattleTypes(JSON.parse(JSON.stringify(localSharedData)) as SharedData),
    staleTime: Infinity,
    refetchOnWindowFocus: false,
  });
}

